export function hamming(a, b) {
  if (typeof a !== "string" || typeof b !== "string") {
    throw new TypeError("hamming: both arguments must be strings");
  }
  const ac = Array.from(a);
  const bc = Array.from(b);
  if (ac.length !== bc.length) {
    throw new RangeError("hamming: strings must have equal length (in code points)");
  }
  let dist = 0;
  for (let i = 0; i < ac.length; i++) {
    if (ac[i] !== bc[i]) dist++;
  }
  return dist;
}

export function hammingBits(x, y) {
  const isBig = typeof x === "bigint" || typeof y === "bigint";

  if (isBig) {
    if (typeof x !== "bigint" || typeof y !== "bigint") {
      throw new TypeError("hammingBits: both arguments must be BigInt when one is BigInt");
    }
    if (x < 0n || y < 0n) throw new RangeError("hammingBits: integers must be non-negative");
    let z = x ^ y;
    let count = 0;
    while (z) {
      count += Number(z & 1n);
      z >>= 1n;
    }
    return count;
  }

  // Numbers
  if (typeof x !== "number" || typeof y !== "number") {
    throw new TypeError("hammingBits: both arguments must be numbers or BigInt");
  }
  if (!Number.isInteger(x) || !Number.isInteger(y)) {
    throw new TypeError("hammingBits: numbers must be integers");
  }
  if (x < 0 || y < 0) {
    throw new RangeError("hammingBits: integers must be non-negative");
  }
  // Use BigInt internally to avoid shifting limits on large numbers
  let zx = BigInt(x);
  let zy = BigInt(y);
  let z = zx ^ zy;
  let count = 0;
  while (z) {
    count += Number(z & 1n);
    z >>= 1n;
  }
  return count;
}
